//! Immutable frame description — the UI DSL.
//! The event loop builds snapshots; the render actor draws them.
//! Zero blocking I/O in the event loop by design.

use crate::model::VisibleRegion;
use crate::ui::elements::Element;

#[derive(Clone)]
pub struct Snapshot {
    pub elements: Vec<Element>,
    pub line_counts: Vec<usize>,
    pub total_lines: usize,
    pub input: String,
    pub cursor_pos: usize,
    pub hint_text: String,
    pub at_suggestions: Option<Vec<String>>,
    pub at_selected: Option<usize>,
    pub turn_active: bool,
    pub spinner_frame: char,
    pub scroll: usize,
    /// Elapsed seconds since turn started. Captured at snapshot creation time.
    pub turn_elapsed_secs: Option<f64>,
    pub provider: String,
    pub model: String,
    /// Active theme name for the render actor
    pub theme_name: String,
    /// Current thinking level for status display
    pub thinking_level: crate::model::ThinkingLevel,
    /// Flash countdown for invalid input feedback.
    pub input_flash: u8,
    /// Placeholder text shown when input is empty.
    pub placeholder: String,
    /// Queue count (pending messages in queue)
    pub queue_count: usize,
    /// Currently open dialog state for rendering overlays.
    pub dialog: Option<crate::commands::DialogState>,
    /// Filtered command list for palette rendering (name, description, category).
    pub palette_items: Vec<(String, String, String)>,
}

impl Snapshot {
    pub fn element_count(&self) -> usize {
        self.elements.len()
    }

    pub fn visible(&self, skip: usize, take: usize) -> &[Element] {
        let start = skip.min(self.elements.len());
        let end = (start + take).min(self.elements.len());
        &self.elements[start..end]
    }

    pub fn visible_scroll(&self, visible_height: usize) -> VisibleRegion<'_> {
        if self.elements.is_empty() || visible_height == 0 {
            return VisibleRegion { elements: &[], skip_lines: 0 };
        }

        let total = self.total_lines;
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);

        let viewport_end = total.saturating_sub(scroll);
        let viewport_start = viewport_end.saturating_sub(visible_height);

        let mut cum = 0usize;
        let mut start_idx = 0;
        let mut skip_lines = 0;

        for (i, count) in self.line_counts.iter().enumerate() {
            let next_cum = cum + count;
            if next_cum > viewport_start {
                start_idx = i;
                skip_lines = viewport_start.saturating_sub(cum);
                break;
            }
            cum = next_cum;
        }

        let mut end_idx = self.elements.len();
        cum = 0;
        for (i, count) in self.line_counts.iter().enumerate() {
            cum += count;
            if cum >= viewport_end {
                end_idx = i + 1;
                break;
            }
        }

        VisibleRegion {
            elements: &self.elements[start_idx..end_idx.min(self.elements.len())],
            skip_lines,
        }
    }

    pub fn scroll_offset(&self, visible_height: usize) -> u16 {
        let max_scroll = self.total_lines.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        max_scroll.saturating_sub(scroll).min(u16::MAX as usize) as u16
    }

    pub fn scrollbar_metrics(&self, visible_height: usize) -> (usize, usize) {
        let total = self.total_lines;
        if total <= visible_height || visible_height == 0 {
            return (0, 0);
        }
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        let position = max_scroll.saturating_sub(scroll);
        let track = visible_height;
        let thumb = (visible_height * visible_height / total).max(1);
        #[allow(clippy::manual_checked_ops)]
        let thumb_offset = if max_scroll > 0 {
            position * (track - thumb) / max_scroll
        } else {
            0
        };
        (thumb, thumb_offset)
    }
}

//! Session persistence — JSON files in ~/.runie/sessions/

use crate::model::ChatMessage;
use serde::{Deserialize, Serialize};
use std::path::PathBuf;

/// Session snapshot — serializable conversation state
#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct Session {
    pub name: String,
    pub created_at: f64,
    pub updated_at: f64,
    pub messages: Vec<ChatMessage>,
    pub provider: String,
    pub model: String,
    pub theme_name: String,
    pub thinking_level: crate::model::ThinkingLevel,
}

/// Session store — handles save/load/list/delete
#[derive(Debug, Clone)]
pub struct Store {
    pub dir: PathBuf,
}

impl Store {
    /// Default store — uses OS data dir (~/.local/share/runie/sessions on Linux)
    pub fn default_store() -> Option<Self> {
        dirs::data_dir().map(|d| Self::new(d.join("runie").join("sessions")))
    }

    /// Store with explicit directory (for testing)
    pub fn new(dir: PathBuf) -> Self {
        Self { dir }
    }

    pub fn path(&self, name: &str) -> PathBuf {
        self.dir.join(format!("{}.json", name))
    }

    fn ensure_dir(&self) -> std::io::Result<()> {
        std::fs::create_dir_all(&self.dir)
    }

    /// Save session to JSON file
    pub fn save(&self, name: &str, session: &Session) -> anyhow::Result<()> {
        self.ensure_dir()?;
        let json = serde_json::to_string_pretty(session)?;
        std::fs::write(self.path(name), json)?;
        Ok(())
    }

    /// Load session from JSON file
    pub fn load(&self, name: &str) -> anyhow::Result<Session> {
        let json = std::fs::read_to_string(self.path(name))?;
        let session: Session = serde_json::from_str(&json)?;
        Ok(session)
    }

    /// List all saved session names (sorted)
    pub fn list(&self) -> anyhow::Result<Vec<String>> {
        if !self.dir.exists() {
            return Ok(Vec::new());
        }
        let mut names = Vec::new();
        for entry in std::fs::read_dir(&self.dir)? {
            let entry = entry?;
            let name = entry.file_name().to_string_lossy().to_string();
            if let Some(stem) = name.strip_suffix(".json") {
                names.push(stem.to_string());
            }
        }
        names.sort();
        Ok(names)
    }

    /// Delete a session file
    pub fn delete(&self, name: &str) -> anyhow::Result<()> {
        std::fs::remove_file(self.path(name))?;
        Ok(())
    }
}



pub fn default_store() -> Option<Store> {
    if let Ok(dir) = std::env::var("RUNIE_SESSIONS_DIR") {
        return Some(Store::new(PathBuf::from(dir)));
    }
    Store::default_store()
}

pub fn save(name: &str, session: &Session) -> anyhow::Result<()> {
    default_store()
        .ok_or_else(|| anyhow::anyhow!("No data directory"))?
        .save(name, session)
}

pub fn load(name: &str) -> anyhow::Result<Session> {
    default_store()
        .ok_or_else(|| anyhow::anyhow!("No data directory"))?
        .load(name)
}

pub fn list() -> anyhow::Result<Vec<String>> {
    default_store()
        .ok_or_else(|| anyhow::anyhow!("No data directory"))?
        .list()
}

pub fn delete(name: &str) -> anyhow::Result<()> {
    default_store()
        .ok_or_else(|| anyhow::anyhow!("No data directory"))?
        .delete(name)
}





#[cfg(test)]
mod tests {
    use super::*;
    use crate::model::{ChatMessage, Role};
    use std::sync::atomic::{AtomicU64, Ordering};

    static COUNTER: AtomicU64 = AtomicU64::new(0);

    fn tmp_store() -> Store {
        let n = COUNTER.fetch_add(1, Ordering::SeqCst);
        let dir = std::env::temp_dir().join(format!("runie_test_{}_{}", std::process::id(), n));
        let _ = std::fs::remove_dir_all(&dir);
        Store::new(dir)
    }

    fn sample_session(name: &str) -> Session {
        Session {
            name: name.to_string(),
            created_at: 1.0,
            updated_at: 2.0,
            messages: vec![
                ChatMessage { role: Role::User, content: "hi".into(), timestamp: 1.0, id: "req.0".into(), ..Default::default()},
                ChatMessage { role: Role::Assistant, content: "hello".into(), timestamp: 2.0, id: "resp.0".into(), ..Default::default()},
            ],
            provider: "mock".into(),
            model: "echo".into(),
            theme_name: "silkcircuit-neon".into(),
            thinking_level: crate::model::ThinkingLevel::Off,
        }
    }

    #[test]
    fn save_creates_json_file() {
        let store = tmp_store();
        let session = sample_session("test1");
        store.save("test1", &session).unwrap();
        assert!(store.path("test1").exists(), "JSON file should exist");
    }

    #[test]
    fn load_roundtrip() {
        let store = tmp_store();
        let original = sample_session("roundtrip");
        store.save("roundtrip", &original).unwrap();
        let loaded = store.load("roundtrip").unwrap();
        assert_eq!(loaded.name, "roundtrip");
        assert_eq!(loaded.messages.len(), 2);
        assert_eq!(loaded.messages[0].role, Role::User);
        assert_eq!(loaded.messages[0].content, "hi");
        assert_eq!(loaded.provider, "mock");
        assert_eq!(loaded.model, "echo");
    }

    #[test]
    fn list_returns_sorted_names() {
        let store = tmp_store();
        store.save("beta", &sample_session("beta")).unwrap();
        store.save("alpha", &sample_session("alpha")).unwrap();
        store.save("gamma", &sample_session("gamma")).unwrap();
        let names = store.list().unwrap();
        assert_eq!(names, vec!["alpha", "beta", "gamma"]);
    }

    #[test]
    fn list_empty_dir_returns_empty() {
        let store = tmp_store();
        let names = store.list().unwrap();
        assert!(names.is_empty());
    }

    #[test]
    fn load_missing_session_fails() {
        let store = tmp_store();
        let result = store.load("nonexistent");
        assert!(result.is_err());
    }

    #[test]
    fn delete_removes_session() {
        let store = tmp_store();
        store.save("to_delete", &sample_session("to_delete")).unwrap();
        assert!(store.path("to_delete").exists());
        store.delete("to_delete").unwrap();
        assert!(!store.path("to_delete").exists());
    }

    #[test]
    fn serialize_role_roundtrip() {
        let role = Role::Assistant;
        let json = serde_json::to_string(&role).unwrap();
        let decoded: Role = serde_json::from_str(&json).unwrap();
        assert_eq!(role, decoded);
    }

    #[test]
    fn serialize_chat_message_roundtrip() {
        let msg = ChatMessage { role: Role::User, content: "test".into(), timestamp: 1.5, id: "req.1".into(), ..Default::default()};
        let json = serde_json::to_string(&msg).unwrap();
        let decoded: ChatMessage = serde_json::from_str(&json).unwrap();
        assert_eq!(msg.role, decoded.role);
        assert_eq!(msg.content, decoded.content);
        assert_eq!(msg.timestamp, decoded.timestamp);
        assert_eq!(msg.id, decoded.id);
    }

    #[test]
    fn serialize_session_full_roundtrip() {
        let session = sample_session("full");
        let json = serde_json::to_string_pretty(&session).unwrap();
        let decoded: Session = serde_json::from_str(&json).unwrap();
        assert_eq!(session.name, decoded.name);
        assert_eq!(session.messages.len(), decoded.messages.len());
        assert_eq!(session.theme_name, decoded.theme_name);
        assert_eq!(session.thinking_level, decoded.thinking_level);
    }

    #[test]
    fn session_persists_provider() {
        let mut session = sample_session("provider_test");
        session.messages[1].provider = "openai".to_string();
        let store = tmp_store();
        store.save("provider_test", &session).unwrap();
        let loaded = store.load("provider_test").unwrap();
        assert_eq!(loaded.messages[1].provider, "openai");
    }
}

